mapper.select:
select id, fonds_code as "fondsCode", fonds_name as "fondsName", enabled, sort_order as "sortOrder", created_at as "createdAt", updated_at as "updatedAt" from am_archive_fonds where deleted_flag = false
and enabled = #{enabled}
order by sort_order, id

select id, parent_id as "parentId", category_code as "categoryCode", category_name as "categoryName", record_table_name as "recordTableName", table_status as "tableStatus", built_at as "builtAt", enabled, sort_order as "sortOrder", created_at as "createdAt", updated_at as "updatedAt" from am_archive_category where deleted_flag = false
and enabled = #{enabled}
order by parent_id nulls first, sort_order, id

select id, category_id as "categoryId", field_code as "fieldCode", field_name as "fieldName", field_type as "fieldType", column_name as "columnName", text_length as "textLength", decimal_precision as "decimalPrecision", decimal_scale as "decimalScale", edit_control as "editControl", list_visible as "listVisible", list_width as "listWidth", list_sort_order as "listSortOrder", detail_visible as "detailVisible", detail_col_span as "detailColSpan", detail_sort_order as "detailSortOrder", edit_visible as "editVisible", edit_col_span as "editColSpan", edit_sort_order as "editSortOrder", exact_searchable as "exactSearchable", full_text_searchable as "fullTextSearchable", enabled, sort_order as "sortOrder", created_at as "createdAt", updated_at as "updatedAt" from am_archive_field where category_id = #{categoryId} and deleted_flag = false
and enabled = #{enabled}
order by sort_order, id

select count(*)
from information_schema.tables
where table_schema = current_schema() and table_name = #{tableName}

select count(*)
from information_schema.columns
where table_schema = current_schema()
  and table_name = #{tableName}
  and column_name = #{columnName}

select count(*)
from pg_indexes
where schemaname = current_schema() and indexname = #{indexName}

select r.id, d.fonds_code, r.category_code, r.category_name, r.archive_no, r.archive_status, r.process_status, r.archive_year, r.locked_flag, r.lock_reason, r.locked_by, r.locked_at ${selectColumns} from am_archive_record r join ${tableName} d on d.id = r.id where r.deleted_flag = false and d.deleted_flag = false and r.category_code = #{categoryCode}
and d.fonds_code = #{fondsCode}
and d.${condition.columnName} = #{condition.value}
and d.${condition.columnName} >= #{condition.value}
and d.${condition.columnName} <= #{condition.value}
and r.id in
#{recordId}
order by
array_position(array[
cast(#{recordId} as bigint)
], r.id)
r.sort_order, r.id desc

