update ${tableName}
set

    ${assignment.columnName} = #{assignment.value}

    , updated_at = localtimestamp
where id = #{id} and deleted_flag = false

update ${tableName}
set deleted_flag = true, updated_at = localtimestamp
where id = #{id} and deleted_flag = false

mapper.select:
select *
from ${tableName}
where id = #{id} and deleted_flag = false

